5	
6	interface EmptyStateAction {
7	  label: string;
8	  href?: string;
9	  onClick?: () => void;
10	}
11	
12	interface EmptyStateProps {
13	  icon?: LucideIcon;
14	  title: string;
15	  description?: string;
16	  action?: EmptyStateAction;
17	  className?: string;
18	}
19	
20	export function EmptyState({
21	  icon: Icon = Inbox,
22	  title,
23	  description,
24	  action,
25	  className,
26	}: EmptyStateProps) {
27	  const content = (
28	    <div
29	      className={cn(
30	        "flex flex-col items-center justify-center gap-3 py-12 text-center",
31	        className,
32	      )}
33	    >
34	      <div className="flex size-12 items-center justify-center rounded-full bg-muted">
35	        <Icon className="size-6 text-muted-foreground" />
36	      </div>
37	      <div>
38	        <h3 className="text-sm font-medium text-foreground">{title}</h3>
39	        {description && (
40	          <p className="mt-1 text-sm text-muted-foreground">{description}</p>
41	        )}
42	      </div>
43	      {action && (
44	        <>
45	          {action.href ? (
46	            <Link href={action.href}>
47	              <Button variant="outline" size="sm">
48	                {action.label}
49	              </Button>
50	            </Link>
51	          ) : (
52	            <Button variant="outline" size="sm" onClick={action.onClick}>
53	              {action.label}
54	            </Button>
55	          )}
56	        </>
57	      )}
58	    </div>
59	  );
60	
61	  return content;
62	}
