1	import { Badge } from "@/components/ui/badge";
2	import { cn } from "@/lib/utils";
3	
4	export type AssetInstanceStatus =
5	  | "IN_STOCK"
6	  | "AVAILABLE"
7	  | "ASSIGNED"
8	  | "IN_USE"
9	  | "RETURNING"
10	  | "REPAIRING"
11	  | "TRANSFERRING"
12	  | "LOST"
13	  | "SCRAPPED";
14	
15	const statusConfig: Record<
16	  AssetInstanceStatus,
17	  { label: string; variant: "default" | "secondary" | "outline" | "destructive" | "ghost" | "link"; className?: string }
18	> = {
19	  IN_STOCK: { label: "在库", variant: "ghost", className: "text-muted-foreground" },
20	  AVAILABLE: { label: "可用", variant: "default", className: "bg-green-500/10 text-green-600 hover:bg-green-500/20 dark:text-green-400" },
21	  ASSIGNED: { label: "已分配", variant: "default", className: "bg-blue-500/10 text-blue-600 hover:bg-blue-500/20 dark:text-blue-400" },
22	  IN_USE: { label: "使用中", variant: "default", className: "bg-teal-500/10 text-teal-600 hover:bg-teal-500/20 dark:text-teal-400" },
23	  RETURNING: { label: "归还中", variant: "outline", className: "border-yellow-400 text-yellow-600 dark:text-yellow-400" },
24	  REPAIRING: { label: "维修中", variant: "outline", className: "border-orange-400 text-orange-600 dark:text-orange-400" },
25	  TRANSFERRING: { label: "调拨中", variant: "outline", className: "border-purple-400 text-purple-600 dark:text-purple-400" },
26	  LOST: { label: "丢失", variant: "destructive" },
27	  SCRAPPED: { label: "已报废", variant: "ghost", className: "text-muted-foreground" },
28	};
29	
30	interface AssetStatusBadgeProps {
31	  status: AssetInstanceStatus;
32	  className?: string;
33	}
34	
35	export function AssetStatusBadge({ status, className }: AssetStatusBadgeProps) {
36	  const config = statusConfig[status] ?? {
37	    label: status,
38	    variant: "outline" as const,
39	  };
40	
41	  return (
42	    <Badge
43	      variant={config.variant}
44	      className={cn(config.className, className)}
45	    >
46	      {config.label}
47	    </Badge>
48	  );
49	}
