9	import { useAuth, type UserRole } from "@/lib/auth-context";
10	import {
11	  LayoutDashboard,
12	  Laptop,
13	  ClipboardPlus,
14	  Ticket,
15	  Bot,
16	  Bell,
17	  Settings,
