34	export type NavItem = {
35	  label: string;
36	  href: string;
37	  icon: LucideIcon;
38	  roles: UserRole[];
39	};
40	
41	const navItems: NavItem[] = [
42	  { label: "首页", href: "/home", icon: LayoutDashboard, roles: ["EMPLOYEE", "MANAGER", "IT_ADMIN", "EXECUTIVE"] },
43	  { label: "我的资产", href: "/my-assets", icon: Laptop, roles: ["EMPLOYEE", "MANAGER"] },
