```tsx
"use client"

import * as React from "react"
import { Menu } from "@base-ui/react/menu"
import { cn } from "@/lib/utils"
import { ChevronDownIcon, CheckIcon } from "lucide-react"

interface SelectContextValue {
  value?: string
  onValueChange?: (value: string) => void
}

const SelectContext = React.createContext<SelectContextValue>({})

function Select({ value, onValueChange, children, ...props }: Menu.Root.Props & { value?: string; onValueChange?: (value: string) => void }) {
  return (
    <SelectContext.Provider value={{ value, onValueChange }}>
      <Menu.Root data-slot="select" {...props}>
        {children}
      </Menu.Root>
    </SelectContext.Provider>
  )
}

function SelectTrigger({ className, children, ...props }: Menu.Trigger.Props) {
  return (
    <Menu.Trigger
      data-slot="select-trigger"
      className={cn(
        "flex h-8 w-full items-center justify-between gap-2 rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
      <ChevronDownIcon className="size-4 text-muted-foreground" />
    </Menu.Trigger>
  )
}

function SelectValue({ placeholder, className, children, ...props }: React.ComponentProps<"span"> & { placeholder?: string }) {
  return (
    <span
      data-slot="select-value"
      className={cn("text-sm", !children && !placeholder && "text-muted-foreground", className)}
      {...props}
    >
      {children ?? placeholder}
    </span>
  )
}

function SelectContent({ align = "start", sideOffset = 4, className, ...props }: Menu.Popup.Props & Menu.Positioner.Props) {
  const { align: _, sideOffset: __, ...popupProps } = props as any
  return (
    <Menu.Portal>
      <Menu.Positioner
        className="isolate z-50 outline-none"
        align={align}
        sideOffset={sideOffset}
      >
        <Menu.Popup
          data-slot="select-content"
          className={cn(
            "z-50 max-h-(--available-height) w-(--anchor-width) min-w-32 origin-(--transform-origin) overflow-x-hidden overflow-y-auto rounded-lg bg-popover p-1 text-popover-foreground shadow-md ring-1 ring-foreground/10 duration-100 outline-none data-[side=bottom]:slide-in-from-top-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:overflow-hidden data-closed:fade-out-0 data-closed:zoom-out-95",
            className
          )}
          {...popupProps}
        />
      </Menu.Positioner>
    </Menu.Portal>
  )
}

function SelectItem({ value, className, children, ...props }: Menu.Item.Props & { value: string }) {
  const ctx = React.useContext(SelectContext)
  const isSelected = ctx.value === value

  return (
    <Menu.Item
      data-slot="select-item"
      data-selected={isSelected || undefined}
      onClick={(e: React.MouseEvent) => {
        ctx.onValueChange?.(value)
        props.onClick?.(e)
      }}
      className={cn(
        "relative flex cursor-default items-center gap-1.5 rounded-md px-1.5 py-1 text-sm outline-hidden select-none focus:bg-accent focus:text-accent-foreground data-disabled:pointer-events-none data-disabled:opacity-50 data-selected:font-medium [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        className
      )}
      {...props}
    >
      {isSelected && (
        <span className="absolute right-2 flex items-center">
          <CheckIcon className="size-3.5" />
        </span>
      )}
      {children}
    </Menu.Item>
  )
}

function SelectGroup({ ...props }: Menu.Group.Props) {
  return <Menu.Group data-slot="select-group" {...props} />
}

function SelectLabel({ className, ...props }: Menu.GroupLabel.Props) {
  return (
    <Menu.GroupLabel
      data-slot="select-label"
      className={cn("px-1.5 py-1 text-xs font-medium text-muted-foreground", className)}
      {...props}
    />
  )
}

function SelectSeparator({ className, ...props }: Menu.Separator.Props) {
  return (
    <Menu.Separator
      data-slot="select-separator"
      className={cn("-mx-1 my-1 h-px bg-border", className)}
      {...props}
    />
  )
}

export {
  Select,
  SelectTrigger,
  SelectValue,
  SelectContent,
  SelectItem,
  SelectGroup,
  SelectLabel,
  SelectSeparator,
}
```

