"use client"

import * as React from "react"
import { Menu } from "@base-ui/react/menu"

import { cn } from "@/lib/utils"
import { ChevronDownIcon, CheckIcon } from "lucide-react"

interface SelectContextValue {
  value?: string
  onValueChange?: (value: string) => void
}

const SelectContext = React.createContext<SelectContextValue>({})

function Select({ value, onValueChange, children, ...props }: Menu.Root.Props & { value?: string; onValueChange?: (value: string) => void }) {
  return (
    <SelectContext.Provider value={{ value, onValueChange }}>
      <Menu.Root data-slot="select" {...props}>
        {children}
      </Menu.Root>
    </SelectContext.Provider>
  )
}

function SelectTrigger({ className, children, ...props }: Menu.Trigger.Props) {
  return (
    <Menu.Trigger
      data-slot="select-trigger"
      className={cn(
        "flex h-8 w-full items-center justify-between gap-2 rounded-lg border border-input bg-background px-3 py-2 text-sm outline-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      {...props}
    >
      {children}
      <ChevronDownIcon className="size-4 text-muted-foreground" />
    </Menu.Trigger>
  )
}

function SelectValue({ placeholder, className, children, ...props }: React.ComponentProps<"span"> & { placeholder?: string }) {
  return (
    <span
      data-slot="select-value"
      className={cn("text-sm", !children && "text-muted-foreground", className)}
      {...props}
    >
      {children ?? placeholder}
    </span>
  )
}

function SelectContent({
  align = "start",
  alignOffset = 0,
  side = "bottom",
  sideOffset = 4,
  className,
  ...props
}: Menu.Popup.Props &
  Pick<Menu.Positioner.Props, "align" | "alignOffset" | "side" | "sideOffset">) {
  return (
    <Menu.Portal>
      <Menu.Positioner
        className="isolate z-50 outline-none"
        align={align}
        alignOffset={alignOffset}
        side={side}
        sideOffset={sideOffset}
      >
        <Menu.Popup
          data-slot="select-content"
          className={cn(
            "z-50 max-h-(--available-height) w-(--anchor-width) min-w-32 origin-(--transform-origin) overflow-x-hidden overflow-y-auto rounded-lg bg-popover p-1 text-popover-foreground shadow-md ring-1 ring-foreground/10 duration-100 outline-none data-[side=bottom]:slide-in-from-top-2 data-[side=inline-end]:slide-in-from-left-2 data-[side=inline-start]:slide-in-from-right-2 data-[side=left]:slide-in-from-right-2 data-[side=right]:slide-in-from-left-2 data-[side=top]:slide-in-from-bottom-2 data-open:animate-in data-open:fade-in-0 data-open:zoom-in-95 data-closed:animate-out data-closed:overflow-hidden data-closed:fade-out-0 data-closed:zoom-out-95",
            className
          )}
          {...props}
        />
      </Menu.Positioner>
    </Menu.Portal>
  )
}

function SelectItem({ value, className, children, ...props }: Menu.Item.Props & { value: string }) {
  const ctx = React.useContext(SelectContext)
  const isSelected = ctx.value === value

  return (
    <Menu.Item
      data-slot="select-item"
      data-selected={isSelected || undefined}
      onClick={(event: React.MouseEvent) => {
        ctx.onValueChange?.(value)
        props.onClick?.(event)
      }}
      className={cn(
        "relative flex cursor-default items-center gap-1.5 rounded-md py-1 pl-1.5 pr-8 text-sm outline-hidden select-none focus:bg-accent focus:text-accent-foreground data-disabled:pointer-events-none data-disabled:opacity-50 data-selected:font-medium [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
        className
      )}
      {...props}
    >
      {children}
      {isSelected && (
        <span className="pointer-events-none absolute right-2 flex items-center justify-center">
          <CheckIcon className="size-3.5" />
        </span>
      )}
    </Menu.Item>
  )
}

function SelectGroup({ ...props }: Menu.Group.Props) {
  return <Menu.Group data-slot="select-group" {...props} />
}

function SelectLabel({ className, ...props }: Menu.GroupLabel.Props) {
  return (
    <Menu.GroupLabel
      data-slot="select-label"
      className={cn("px-1.5 py-1 text-xs font-medium text-muted-foreground", className)}
      {...props}
    />
  )
}

function SelectSeparator({ className, ...props }: Menu.Separator.Props) {
  return (
    <Menu.Separator
      data-slot="select-separator"
      className={cn("-mx-1 my-1 h-px bg-border", className)}
      {...props}
    />
  )
}

export {
  Select,
  SelectTrigger,
  SelectValue,
  SelectContent,
  SelectItem,
  SelectGroup,
  SelectLabel,
  SelectSeparator,
}

import { cn } from "@/lib/utils"

interface PageHeaderProps {
  title: string
  description?: string
  actions?: React.ReactNode
  className?: string
}

export function PageHeader({ title, description, actions, className }: PageHeaderProps) {
  return (
    <div className={cn("flex items-start justify-between gap-4", className)}>
      <div className="space-y-1">
        <h1 className="text-2xl font-bold tracking-tight">{title}</h1>
        {description && <p className="text-sm text-muted-foreground">{description}</p>}
      </div>
      {actions && <div className="flex items-center gap-2">{actions}</div>}
    </div>
  )
}

import { cn } from "@/lib/utils"
import { Badge } from "@/components/ui/badge"

interface TicketStatusBadgeProps {
  status: string
  className?: string
}

const ticketStatusMap: Record<string, { label: string; variant: "default" | "secondary" | "destructive" | "outline"; className?: string }> = {
  SUBMITTED: { label: "已提交", variant: "secondary" },
  PENDING_MANAGER_1: { label: "待主管审批", variant: "default", className: "bg-status-blue/10 text-status-blue dark:text-status-blue" },
  PENDING_MANAGER_2: { label: "待上级审批", variant: "default", className: "bg-status-blue/10 text-status-blue dark:text-status-blue" },
  PENDING_IT: { label: "待IT处理", variant: "default", className: "bg-status-yellow/10 text-status-yellow dark:text-status-yellow" },
  APPROVED: { label: "已通过", variant: "default", className: "bg-status-green/10 text-status-green dark:text-status-green" },
  REJECTED: { label: "已驳回", variant: "destructive" },
  IN_PROGRESS: { label: "处理中", variant: "default", className: "bg-status-purple/10 text-status-purple dark:text-status-purple" },
  COMPLETED: { label: "已完成", variant: "default", className: "bg-status-green/10 text-status-green dark:text-status-green" },
  CANCELLED: { label: "已取消", variant: "secondary" },
}

export function TicketStatusBadge({ status, className }: TicketStatusBadgeProps) {
  const config = ticketStatusMap[status] ?? { label: status, variant: "secondary" as const }
  return (
    <Badge variant={config.variant} className={cn(config.className, className)}>
      {config.label}
    </Badge>
  )
}

